const E = [new KV('', '')];
const JSON_H = [new KV('Accept', 'application/json')];
const MD_API = 'https://api.mangadex.org';
const MD_SITE = 'https://mangadex.org';
const PLACEHOLDER = 'https://www.shutterstock.com/image-vector/default-ui-image-placeholder-wireframes-600nw-1037719192.jpg';

function saved(){ return document.getElementById('ketsu-final-data'); }

function meta(){
  try { return JSON.parse(saved().textContent || saved().innerText || '{}'); }
  catch(e){ return {}; }
}

function done(){
  try { window.webkit.messageHandlers.EXECUTE_KETSU_ASYNC.postMessage(''); } catch(e){}
}

function req(url, referer){
  let h = referer ? [new KV('Referer', referer)] : E;
  return new MR(url, 'GET', h, null);
}

function apiReq(url){
  return new MR(url, 'GET', JSON_H, null);
}

function currentUrl(){
  let m = meta();
  return m && m.request && m.request.url ? m.request.url : location.href;
}

function parseJsonText(txt){
  txt = (txt || '').trim();
  if(!txt) throw new Error('empty');
  try { return JSON.parse(txt); } catch(e) {}
  let a = txt.indexOf('{');
  let b = txt.lastIndexOf('}');
  if(a >= 0 && b > a) return JSON.parse(txt.slice(a, b + 1));
  throw new Error('not json');
}

function parseJsonFromPage(){
  let candidates = [];
  try { candidates.push(document.querySelector('pre')?.textContent || ''); } catch(e){}
  try { candidates.push(document.body?.innerText || ''); } catch(e){}
  try { candidates.push(document.documentElement?.innerText || ''); } catch(e){}
  try { 
    let m = meta();
    candidates.push(m.responseInfo?.httpBody || '');
    candidates.push(m.responseInfo?.body || '');
  } catch(e){}
  for (let txt of candidates) {
    try { return parseJsonText(txt); } catch(e) {}
  }
  throw new Error('Could not parse API JSON from page');
}

async function fetchJSON(url){
  let r = await fetch(url, { headers: { 'Accept': 'application/json' } });
  if(!r.ok) throw new Error('HTTP ' + r.status);
  return await r.json();
}

function titleOf(m){
  let t = (m.attributes && m.attributes.title) || {};
  return t.en || t["ja-ro"] || t.ja || t["ko-ro"] || t.ko || Object.values(t)[0] || 'Untitled';
}

function descOf(m){
  let d = (m.attributes && m.attributes.description) || {};
  return d.en || Object.values(d)[0] || '';
}

function coverFile(m){
  let rels = m.relationships || [];
  let cover = rels.find(r => r.type === 'cover_art');
  return cover && cover.attributes ? cover.attributes.fileName : '';
}

function coverReq(manga){
  let file = coverFile(manga);
  if(!manga || !manga.id || !file) return req(PLACEHOLDER);
  return req('https://i1.wp.com/uploads.mangadex.org/covers/' + manga.id + '/' + file + '.512.jpg');
}

function mangaInfoReq(id){
  return apiReq(MD_API + '/manga/' + id + '?includes%5B%5D=cover_art');
}

function atHomeReq(chapterId){
  return apiReq(MD_API + '/at-home/server/' + chapterId);
}

function chapterLabel(attrs){
  let ch = attrs && attrs.chapter ? String(attrs.chapter) : '?';
  return 'Chapter ' + ch;
}

function errorCard(title, msg){
  return new Data(
    req(PLACEHOLDER),
    title || 'Parser error',
    msg || 'Unknown error',
    '', '', '', '',
    false,
    req(MD_SITE),
    false
  );
}

function searchTerm(){
  let u = currentUrl();
  try {
    let p = new URL(u).searchParams;
    let raw = p.get('title') || p.get('q') || p.get('query') || p.get('ketsu_search') || p.get('search') || '';
    if(raw && raw !== '<searched>') return raw;
  } catch(e){}
  try {
    let body = document.body ? document.body.innerText : '';
    let m = body.match(/Searched:\s*([^\n\r]+)/i);
    if(m) return m[1].trim();
  } catch(e){}
  return '';
}

function cleanText(s, max){
  s = (s || '').replace(/\s+/g, ' ').trim();
  if(max && s.length > max) return s.slice(0, max - 3) + '...';
  return s;
}

function contentQuery(){
  return '&availableTranslatedLanguage%5B%5D=en' +
    '&hasAvailableChapters=true' +
    '&contentRating%5B%5D=safe' +
    '&contentRating%5B%5D=suggestive';
}

function titleCard(manga, label){
  let a = manga.attributes || {};
  let status = a.status || 'Manga';
  let year = a.year ? String(a.year) : '';
  let rating = a.contentRating || '';
  return new Data(
    coverReq(manga),
    titleOf(manga),
    cleanText(descOf(manga), 95),
    label || status,
    'MangaDex',
    year,
    rating,
    false,
    mangaInfoReq(manga.id),
    false
  );
}

async function mangaList(url, label, max){
  let out = [];
  try {
    let json = await fetchJSON(url);
    for (const manga of (json.data || [])) {
      if(!manga || !manga.id) continue;
      out.push(titleCard(manga, label));
      if(out.length >= max) break;
    }
  } catch(e) {}
  return out;
}

async function latestCards(json, max){
  let out = [];
  let seen = {};
  let rows = [];
  let ids = [];
  let items = (json.data || []).filter(x => x.type === 'chapter');

  for(const item of items){
    let attrs = item.attributes || {};
    let mangaRel = (item.relationships || []).find(r => r.type === 'manga');
    let mangaId = mangaRel ? mangaRel.id : '';
    if(!mangaId || seen[mangaId]) continue;
    seen[mangaId] = true;
    ids.push(mangaId);
    rows.push({ item: item, attrs: attrs, mangaRel: mangaRel, mangaId: mangaId });
    if(rows.length >= max) break;
  }

  let mangaMap = {};
  if(ids.length > 0){
    try {
      let url = MD_API + '/manga?limit=' + ids.length + '&includes%5B%5D=cover_art';
      for (const id of ids) url += '&ids%5B%5D=' + id;
      let batch = await fetchJSON(url);
      for (const m of (batch.data || [])) mangaMap[m.id] = m;
    } catch(e) {}
  }

  for(const row of rows){
    let attrs = row.attrs;
    let mangaId = row.mangaId;

    let manga = mangaMap[mangaId] || row.mangaRel || { id: mangaId, attributes: { title: { en: 'MangaDex Title' } }, relationships: [] };

    let chap = chapterLabel(attrs);
    out.push(new Data(
      coverReq(manga),
      titleOf(manga),
      chap + (attrs.title ? ': ' + attrs.title : ''),
      chap,
      'Manga',
      '',
      '',
      false,
      mangaInfoReq(mangaId),
      false
    ));
  }

  return out;
}

async function run(){
  let output = [];
  let featured = [];
  let latest = [];
  let more = [];
  let popular = [];
  let newlyAdded = [];
  let completed = [];

  try {
    let json = parseJsonFromPage();
    let updates = await latestCards(json, 31);
    featured = updates.slice(0, 1);
    latest = updates.slice(1, 13);
    more = updates.slice(13, 31);

    let base = MD_API + '/manga?limit=18&includes%5B%5D=cover_art' + contentQuery();
    popular = await mangaList(base + '&status%5B%5D=ongoing&order%5BfollowedCount%5D=desc', 'Ongoing', 18);
    newlyAdded = await mangaList(base + '&order%5BcreatedAt%5D=desc', 'New', 18);
    completed = await mangaList(base + '&status%5B%5D=completed&order%5BfollowedCount%5D=desc', 'Complete', 18);

    if(featured.length === 0 && latest.length === 0) {
      latest.push(errorCard('No latest chapters', 'MangaDex returned no latest English chapters.'));
    }
  } catch(e){
    latest.push(errorCard('Main page error', e.message));
  }

  if(featured.length > 0){
    output.push(new Output('wide11','horizontal','ultraWideFull','leading',new Section('Featured Update',true),null,featured));
  }
  if(latest.length > 0){
    output.push(new Output('normal4','horizontal','longTripletsDouble','leading',new Section('Latest Updates',true),null,latest));
  }
  if(popular.length > 0){
    output.push(new Output('normal4','horizontal','longTripletsDouble','leading',new Section('Popular Ongoing',true),null,popular));
  }
  if(newlyAdded.length > 0){
    output.push(new Output('normal4','horizontal','longTripletsDouble','leading',new Section('Newly Added',true),null,newlyAdded));
  }
  if(completed.length > 0){
    output.push(new Output('normal4','horizontal','longTripletsDouble','leading',new Section('Completed Picks',true),null,completed));
  }
  if(more.length > 0){
    output.push(new Output('normal4','horizontal','longTripletsDouble','leading',new Section('More Updates',true),null,more));
  }

  let obj = new MainPage(new MR('', 'GET', E, null), new Extra([new Commands('', E)], E), new JC(false,false,''), output);
  saved().textContent = JSON.stringify(obj);
  done();
}
setTimeout(function(){ run(); }, 700);
} catch(e){
  console.error(e.message);
  done();
}

