  tripletsConstant:'tripletsConstant', tripletsDoubleConstant:'tripletsDoubleConstant', tripletsFullConstant:'tripletsFullConstant', tripletsFullDoubleConstant:'tripletsFullDoubleConstant',
  longTriplets:'longTriplets', longTripletsDouble:'longTripletsDouble', longTripletsFull:'longTripletsFull', longTripletsFullDouble:'longTripletsFullDouble',
  longTripletsConstant:'longTripletsConstant', longTripletsDoubleConstant:'longTripletsDoubleConstant', longTripletsFullConstant:'longTripletsFullConstant', longTripletsFullDoubleConstant:'longTripletsFullDoubleConstant',
