function ModuleRequest(url, method, headers, httpBody){ this.url=url; this.method=method; this.headers=headers; this.httpBody=httpBody; }
function KeyValue(key,value){ this.key=key; this.value=value; }
function Extra(commands, extraInfo){ this.commands=commands; this.extraInfo=extraInfo; }
function Commands(commandName, params){ this.commandName=commandName; this.params=params; }
