function Data(image,title,description,field1,field2,field3,field4,isChapter,link,openInWebView){ this.image=image; this.title=title; this.description=description; this.field1=field1; this.field2=field2; this.field3=field3; this.field4=field4; this.isChapter=isChapter; this.link=link; this.openInWebView=openInWebView || false; }

let emptyKeyValue = [new KeyValue('', '')];
let jsonHeaders = [new KeyValue('Accept', 'application/json')];
let imgHeaders = [new KeyValue('Referer', MD_SITE + '/')];

function clean(s){ return (s || '').replace(/\s+/g,' ').trim(); }
function saved(){ return document.getElementById('ketsu-final-data'); }
function done(){ window.webkit.messageHandlers.EXECUTE_KETSU_ASYNC.postMessage(''); }
function req(url, referer){ return new ModuleRequest(url || PLACEHOLDER, 'get', referer ? [new KeyValue('Referer', referer)] : emptyKeyValue, null); }
function apiReq(url){ return new ModuleRequest(url, 'GET', jsonHeaders, null); }
function encodeQS(v){ return encodeURIComponent(v || ''); }

function currentQuery(){
  try {
    let p = new URL(location.href).searchParams;
    let q = p.get('q') || p.get('title') || p.get('query') || '';
    if(q && q !== '<searched>') return q;
  } catch(e) {}
  try {
    let meta = JSON.parse(saved().textContent || '{}');
    let u = meta.request && meta.request.url ? meta.request.url : '';
    let p = new URL(u).searchParams;
    let q = p.get('q') || p.get('title') || p.get('query') || '';
    if(q && q !== '<searched>') return q;
  } catch(e) {}
  try {
    let body = document.body ? document.body.innerText : '';
    let m = body.match(/Searched:\s*([^\n\r]+)/i);
    if(m) return m[1].trim();
  } catch(e) {}
  return '';
}

function titleOf(m){
  let t = (m.attributes && m.attributes.title) || {};
  return t.en || t['ja-ro'] || t.ja || t['ko-ro'] || t.ko || Object.values(t)[0] || 'MangaDex Title';
}

function descOf(m){
  let d = (m.attributes && m.attributes.description) || {};
  let s = d.en || Object.values(d)[0] || 'Manga';
  s = clean(s);
  return s.length > 120 ? s.slice(0, 120) + '...' : s;
}

function coverFile(m){
  let rels = m.relationships || [];
  let c = rels.find(r => r.type === 'cover_art');
  return c && c.attributes ? c.attributes.fileName : '';
}
function coverReq(m){
  let f = coverFile(m);
  if(!m || !m.id || !f) return req(PLACEHOLDER);
  return req('https://i1.wp.com/uploads.mangadex.org/covers/' + m.id + '/' + f + '.512.jpg');
}
function infoReq(m){ return apiReq(MD_API + '/manga/' + m.id + '?includes%5B%5D=cover_art'); }

function fallbackCard(title, desc){
  return new Data(req(PLACEHOLDER), title, desc || 'No usable results.', '', '', '', '', false, req(MD_SITE + '/search'), false);
}

async function getJSON(url){
  let r = await fetch(url, { headers: { 'Accept': 'application/json' } });
  if(!r.ok) throw new Error('HTTP ' + r.status + ' from MangaDex API');
  return await r.json();
}

async function hasEnglishChapter(id){
  try {
    let url = MD_API + '/chapter?manga=' + id + '&translatedLanguage%5B%5D=en&limit=1&order%5Bchapter%5D=asc';
    let j = await getJSON(url);
    return (j && typeof j.total === 'number') ? j.total > 0 : ((j.data || []).length > 0);
  } catch(e) {
    // If this check fails, keep the result rather than hiding everything.
    return true;
  }
}

async function searchApi(q){
  let url = MD_API + '/manga?title=' + encodeQS(q) +
    '&limit=24' +
    '&includes%5B%5D=cover_art' +
    '&availableTranslatedLanguage%5B%5D=en' +
    '&hasAvailableChapters=true' +
    '&contentRating%5B%5D=safe' +
    '&contentRating%5B%5D=suggestive' +
    '&contentRating%5B%5D=erotica' +
    '&order%5Brelevance%5D=desc';
  let j = await getJSON(url);
  let items = j.data || [];

  let out = [];
  for (let m of items) {
    // This removes search hits like Sip of Poison when MangaDex has no English readable chapters for it.
    if (!(await hasEnglishChapter(m.id))) continue;
    let a = m.attributes || {};
    out.push(new Data(
      coverReq(m),
      titleOf(m),
      descOf(m),
      'Manga',
      'MangaDex',
      a.status || '',
      a.year ? String(a.year) : '',
      false,
      infoReq(m),
      false
    ));
  }
  return out;
}

function finish(results){
  let output = [new Output(
    CellDesings.wide6,
    Orientation.vertical,
    DefaultLayouts.doubletsFull,
    Paging.none,
    new Section('', true),
    null,
    results
  )];
  let obj = new Search(new ModuleRequest('', '', emptyKeyValue, null), new Extra([new Commands('', emptyKeyValue)], emptyKeyValue), '', new JavascriptConfig(false, false, ''), output);
  saved().textContent = JSON.stringify(obj);
  done();
}

async function run(){
  try {
    let q = currentQuery();
    if(!q) return finish([fallbackCard('No search text', 'KETSU did not pass a search query.')]);
    let results = await searchApi(q);
    if(!results.length) results = [fallbackCard('No English chapters found', 'MangaDex has titles for this search, but none with readable English chapters in the API.')];
    finish(results);
  } catch(e) {
    finish([fallbackCard('Search API error', e.message)]);
  }
}

setTimeout(run, 50);
setTimeout(function(){ finish([fallbackCard('Search timeout', 'MangaDex API did not finish in time.')]); }, 14000);

} catch(e) {
  console.error(e.message);
  try { window.webkit.messageHandlers.EXECUTE_KETSU_ASYNC.postMessage(''); } catch(err) {}
}

