async function fetchAllChapters(mangaId){
  let chapters = [];
  let seen = {};
  let offset = 0;
  let total = null;
  let limit = 100;
  let pages = 0;

  while(pages < 60){
    let chapterUrl = MD_API + '/chapter?manga=' + mangaId +
      '&translatedLanguage%5B%5D=en' +
      '&limit=' + limit +
      '&offset=' + offset +
      '&order%5Bchapter%5D=desc' +
      '&order%5Bvolume%5D=desc';

    let chapterJSON = await fetchJSON(chapterUrl);
    let data = chapterJSON.data || [];
    if(total === null) total = Number(chapterJSON.total || 0);
    if(data.length === 0) break;

    for(const ch of data){
      let key = chapterKey(ch);
      if(key && seen[key]) continue;
      if(key) seen[key] = true;
      let a = ch.attributes || {};
      let name = chapterLabel(a) + (a.title ? ': ' + a.title : '');
      chapters.push(new Chapter(name, atHomeReq(ch.id), false));
    }

    offset += data.length;
    pages++;
    if(data.length < limit || (total && offset >= total)) break;
  }

  chapters.reverse();
  return chapters;
}

async function run(){
