    let genres = [];

    if(attrs.tags){
      genres = attrs.tags.map(t => {
        let n = t.attributes && t.attributes.name ? t.attributes.name : {};
        return n.en || Object.values(n)[0] || '';
      }).filter(Boolean);
    }

    let chapters = await fetchAllChapters(mangaId);

    out = new InfoOutput(
      coverReq(manga),
      titleOf(manga),
      mangaInfoReq(mangaId),
      descOf(manga),
      genres,
      attrs.status || '',
      attrs.year ? String(attrs.year) : '',
      attrs.contentRating || '',
      'Chaps: ' + chapters.length,
      chapters
    );
  } catch(e){
    out = new InfoOutput(
      req(PLACEHOLDER),
      'Info error',
      req(MD_SITE),
      e.message,
      [],
      '', '', '', '',
      []
    );
  }

  let obj = new Info(new MR('', '', E, null), new Extra([new Commands('', E)], E), new JC(false,false,''), out);
  saved().textContent = JSON.stringify(obj);
  done();
}
setTimeout(function(){ run(); }, 700);
